function pointToLineDistance(p, p1, p2) {
    const [x0, y0] = p;
    const [x1, y1] = p1;
    const [x2, y2] = p2;
    const area = Math.abs((x2 - x1) * (y1 - y0) - (x1 - x0) * (y2 - y1));
    const base = Math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2);
    if (base === 0) return Math.sqrt((x0 - x1) ** 2 + (y0 - y1) ** 2);
    return area / base;
}

