function treeDistances(n, edges) {
    const adj = Array.from({length: n}, () => []);
    for (const [u, v] of edges) {
        adj[u - 1].push(v - 1);
        adj[v - 1].push(u - 1);
    }

    const subtree = new Array(n).fill(0);
    const sumDown = new Array(n).fill(0);
    const ans = new Array(n).fill(0);

    function dfs1(u, parent) {
        subtree[u] = 1;
        for (const v of adj[u]) {
            if (v !== parent) {
                dfs1(v, u);
                subtree[u] += subtree[v];
                sumDown[u] += sumDown[v] + subtree[v];
            }
        }
    }

    function dfs2(u, parent) {
        for (const v of adj[u]) {
            if (v !== parent) {
                ans[v] = ans[u] - subtree[v] + (n - subtree[v]);
                dfs2(v, u);
            }
        }
    }

    dfs1(0, -1);
    ans[0] = sumDown[0];
    dfs2(0, -1);
    return ans;
}

